+                .ok()
+                .and_then(|raw| raw.trim().parse::<u64>().ok())
+                .unwrap_or(DEFAULT_REQUEST_TIMEOUT_SECS);
+            if timeout_secs == 0 {
+                None
+            } else {
+                Some(std::time::Duration::from_secs(timeout_secs))
+            }
